    "type": "object",
    "properties": {
      "d": { 
        "type": "string", 
        "description": "Data no formato DD/MM/YYYY. Se houver apenas o dia na linha, olhe os cabeçalhos de seção acima para descobrir o mês e ano exatos." 
      },
      "t": { "type": "string", "description": "Texto fiel da descrição" },
      "v": { "type": "number", "description": "Valor numérico decimal (ex: 8.80)" },
      "s": { "type": "string", "description": "Sinal '+' para entrada ou '-' para saída" },
      "c": { "type": "string", "description": "ID exato da Categoria conforme a lista fornecida" },
      "p": { "type": ["string", "null"], "description": "Metadados de parcelamento 'XX/YY' ou null se não houver" }
    },
    "required": ["d", "t", "v", "s", "c"]
  }
}

parameters.jsCode:
/**
 * NORMALIZADOR UNIVERSAL (PEGA TUDO O QUE CHEGAR)
 */

// 1. DADOS DA CONTA
let accountId = "";
let bankName = "";
try {
  const webhook = $('Webhook').first().json;
  const webData = webhook.body || webhook;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
} catch (e) { bankName = "Banco"; }

// 2. CAPTURA DE DADOS (ABERTURA DE ENVELOPE)
let listaBruta = [];
const incomingData = $input.all();

for (const item of incomingData) {
  const data = item.json;

  // Tenta encontrar a lista de transações em qualquer lugar
  let alvo = data.output || data;

  if (Array.isArray(alvo)) {
    listaBruta = listaBruta.concat(alvo);
  } else if (typeof alvo === 'object' && (alvo.t || alvo.d)) {
    listaBruta.push(alvo);
  }
}

// 3. MAPEAMENTO
const anoAtual = new Date().getFullYear();

const final = listaBruta.map((item, index) => {
  const desc = (item.t || "").toString().toUpperCase().trim();
  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') v = v.replace(/[R$\s]/ig, '').replace(',', '.');
  let valorFinal = parseFloat(v) || 0;

  if (item.s === "-" || item.s === "despesa") valorFinal = -Math.abs(valorFinal);
  else valorFinal = Math.abs(valorFinal);

  let dataF = item.d || "";
  if (dataF.includes('/')) {
    let p = dataF.split('/');
    dataF = `${p[2] || anoAtual}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}T12:00:00`;
  }

  return {
    json: {
      account_id: accountId,
      Conta: bankName,
      Data_lancamento: dataF,
      Data_pagamento: dataF,
      Descricao: desc,
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : (["reembolsos", "estorno"].includes(item.c) ? "neutro" : "receita"),
      Categoria: item.c || "outros-gv",
      id_conciliacao: `${desc}-${valorFinal}-${index}`
    }
  };
});

return final;

// Puxa os dados originais direto do Webhook (usando .first() para garantir)
const webhookData = $('Webhook').first().json.body;

const base64 = webhookData.file; 
const fileName = webhookData.fileName;
const userId = webhookData.userId;
const fileType = webhookData.fileType;

const binaryData = Buffer.from(base64, 'base64');

return [{
  json: {
    fileName: fileName,
    fileType: fileType,
    userId: userId
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      binaryData,
      fileName,
      fileType
    )
  }
}];

// Busca o texto diretamente do nó de extração, não do nó anterior
const text = $('Extract from File10').first().json.text || "";
const lines = text.split('\n'); // Divide o texto em linhas reais
const maxCharsPerChunk = 10000; // Limite de segurança
let currentChunk = "";
const chunks = [];

for (const line of lines) {
    // Se a linha atual + o que já temos passar do limite, fecha o lote
    if ((currentChunk.length + line.length) > maxCharsPerChunk && currentChunk.length > 0) {
        chunks.push({ json: { textChunk: currentChunk } });
        currentChunk = "";
    }
    currentChunk += line + "\n";
}

// Adiciona o último pedaço que sobrou
if (currentChunk.length > 0) {
    chunks.push({ json: { textChunk: currentChunk } });
}

return chunks;

