/**
 * NORMALIZADOR DE FATURA - INTELIGÊNCIA UNIVERSAL ANTI-PROJEÇÃO
 */

// 1. CAPTURA DADOS DO WEBHOOK
let accountId = "";
let bankName = "";
let accountName = "";

try {
  const webData = $('Webhook').first().json.body;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
  accountName = webData.accountName || "Conta";
} catch (e) {
  bankName = "Banco";
}

const nomeContaCompleto = `${bankName} - ${accountName}`;

// 2. BUSCA A LISTA DIRETA DA I.A.
let listaBruta = [];
try {
    const aiData = $('LLM Chain PDF2').first().json;
    listaBruta = aiData.output || (Array.isArray(aiData) ? aiData : []);
} catch (e) {
    return [{ json: { erro: "Não foi possível encontrar os dados da LLM Chain" } }];
}

if (listaBruta.length === 0) {
    return [{ json: { aviso: "Lista de transações vazia." } }];
}

const anoAtual = new Date().getFullYear();
const resultado = [];
const parcelamentosVistos = new Map(); // Guarda a assinatura de parcelas para barrar as tabelas do futuro

// 3. MAPEAMENTO E INTELIGÊNCIA DE FILTRO
listaBruta.forEach((item, index) => {
  const descOriginal = (item.t || "").toString().toUpperCase().trim();
  const valorOriginal = parseFloat(item.v) || 0;
  const sinal = item.s || "+";
  let valorFinal = (sinal === "-") ? Math.abs(valorOriginal) : -Math.abs(valorOriginal);

  let dataISO = item.d || "";
  if (dataISO.includes('/')) {
    const p = dataISO.split('/');
    dataISO = `${p[2] || anoAtual}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}T12:00:00`;
  }

  const p = item.p || null;

  // --- TRAVA UNIVERSAL DE PROJEÇÃO DE BANCOS ---
  if (p) {
    const match = p.match(/(\d+)\s*[\/\-de\s]+\s*(\d+)/);
    if (match) {
      const parcelaAtual = parseInt(match[1], 10);
      const totalParcelas = match[2];

      // Cria uma assinatura ignorando os números das parcelas no texto para focar na "raiz" da compra
      const descLimpa = descOriginal.replace(/\(?\s*\d+\s*[\/\-de\s]+\s*\d+\s*\)?/g, '').trim();
      const assinatura = `${descLimpa}_${valorFinal}_${totalParcelas}`;

      if (parcelamentosVistos.has(assinatura)) {
        const parcelaRegistrada = parcelamentosVistos.get(assinatura);

        // Se a parcela que estamos lendo agora for MAIOR que a registrada antes, 
        // é 100% de certeza que o banco começou a listar o futuro (Ex: leu 06/10 antes, e agora achou 07/10).
        if (parcelaAtual > parcelaRegistrada) {
          return; // Aborta e pula para a próxima linha (não gera duplicata)
        }
      }

      // Se for a primeira vez que vemos essa compra, salva a parcela atual dela no 'Map'
      parcelamentosVistos.set(assinatura, parcelaAtual);
    }
  }

  // --- SE PASSOU PELO FILTRO, ADICIONA À LISTA FINAL ---
  resultado.push({
    json: {
      account_id: accountId,
      Conta: nomeContaCompleto,
      Data_lancamento: dataISO,
      Data_pagamento: dataISO,
      Descricao: descOriginal,
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : "receita",
      Categoria: item.c || "outros-gv",
      Classificacao: item.c || "outros-gv",
      p: p,
      id_conciliacao: `${descOriginal}-${valorFinal}-${index}`
    }
  });
});

// 4. FILTRO FINAL DE TOTAIS SUJOS
return resultado.filter(res => {
  const d = res.json.Descricao;
  const ignorar = ["TOTAL", "SUBTOTAL", "RESUMO", "PAGAMENTO EFETUADO", "SALDO ANTERIOR"];
  return !ignorar.some(p => d.includes(p)) && d !== "";
});

// Puxa os dados originais direto do Webhook (usando .first() para garantir)
const webhookData = $('Webhook').first().json.body;

// Agora você extrai tudo de dentro da variável webhookData
const base64 = webhookData.file; 
const fileName = webhookData.fileName;
const userId = webhookData.userId;
const fileType = webhookData.fileType;

const binaryData = Buffer.from(base64, 'base64');

return [{
  json: {
    fileName: fileName,
    fileType: fileType,
    userId: userId
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      binaryData,
      fileName,
      fileType
    )
  }
}];

const finalResults = [];
const hoje = new Date();
hoje.setHours(12, 0, 0, 0);
const hojeIso = hoje.toISOString().split('T')[0];

function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// 1. Definição de variáveis globais com segurança
let userIdFixo = "";
let webhookData = {};

try {
  webhookData = $('Webhook').first().json.body || {};
} catch (e) {
  webhookData = {};
}

try {
  // Busca o userId do nó de código anterior
  userIdFixo = $('Code in JavaScript3').item.json.userId;
} catch (e) {
  userIdFixo = webhookData.userId || "";
}

const ownerIdCalculado = webhookData.ownerId || userIdFixo;

// 2. Loop principal pelos itens recebidos
for (const item of $input.all()) {
  try {
    const transacao = item.json;

    // Garantia de tipos (Strings) para evitar quebras em métodos como .match()
    const descOriginal = String(transacao.Descricao || "").toUpperCase();
    const parcelaIA = String(transacao.p || "").toUpperCase();
    const dataRaw = String(transacao.Data_lancamento || "");

    if (!dataRaw) continue; // Pula se o item não tiver data

    const regex = /(\d+)\s*[\/\-de\s]+\s*(\d+)/i;
    const match = parcelaIA.match(regex) || descOriginal.match(regex);

    // Limpeza da data (remove o tempo se vier no formato ISO)
    const dataLancamentoLimpa = dataRaw.includes('T') ? dataRaw.split('T')[0] : dataRaw;

    // --- LÓGICA DE PROTEÇÃO CONTRA DATAS QUE PARECEM PARCELAS ---
    let isValidInstallment = false;
    if (match) {
      const pAtual = parseInt(match[1]);
      const pTotal = parseInt(match[2]);

      // Só aceita como parcela se o total for maior que a atual e se não for um PIX com data (ex: 06/01)
      if (pAtual <= pTotal && pTotal > 1) {
         // Se for PIX e não houver instrução explícita da IA (campo p), ignoramos o match da descrição
         if (descOriginal.includes("PIX") && !transacao.p) {
           isValidInstallment = false;
         } else {
           isValidInstallment = true;
         }
      }
    }

    if (isValidInstallment && match) {
      const parcelaAtual = parseInt(match[1]);
      const totalParcelas = parseInt(match[2]);
      const descLimpa = descOriginal.replace(/\(\s*\d+\s*[\/\-de\s]+\s*\d+\s*\)/gi, '').replace(regex, '').replace(/\s+/g, ' ').trim();
      const installmentGroupId = generateUUID();

      const fimLoop = totalParcelas - parcelaAtual;
      const dataBase = new Date(dataLancamentoLimpa + 'T12:00:00');

      for (let i = 0; i <= fimLoop; i++) {
        let dP = new Date(dataBase);
        dP.setMonth(dataBase.getMonth() + i);
        const dt = dP.toISOString().split('T')[0];
        const isFuturo = dt > hojeIso;

        finalResults.push({
          json: {
            ...transacao,
            Descricao: `${descLimpa} (${parcelaAtual + i}/${totalParcelas})`,
            Data_lancamento: dt,
            userId: userIdFixo,
            accountId: webhookData.accountId,
            ownerId: ownerIdCalculado,
            confirmed: !isFuturo, 
            paymentDate: isFuturo ? null : (webhookData.paymentDate || transacao.Data_pagamento || null),
            pending_review: true,
            installment_group_id: installmentGroupId,
            installment_number: parcelaAtual + i,
            total_installments: totalParcelas
          }
        });
      }
      continue; // Vai para o próximo item do $input.all()
    }

    // --- CASO NORMAL (SEM PARCELAS OU DATA QUE PARECIA PARCELA) ---
    const dataFinalIso = new Date(dataLancamentoLimpa + 'T12:00:00').toISOString().split('T')[0];
    const isFuturoSimples = dataFinalIso > hojeIso;

    finalResults.push({
      json: {
        ...transacao,
        Data_lancamento: dataFinalIso,
        userId: userIdFixo,
        accountId: webhookData.accountId,
        ownerId: ownerIdCalculado,
        paymentDate: isFuturoSimples ? null : (webhookData.paymentDate || transacao.Data_pagamento || null),
        confirmed: !isFuturoSimples,
        pending_review: false,
        installment_group_id: null,
        installment_number: null,
        total_installments: null
      }
    });

  } catch (err) {
    // Em caso de erro em um item (ex: data inválida), loga o erro e continua para o próximo item
    console.error("Erro ao processar item:", err);
    continue; 
  }
}

return finalResults;

// Busca o texto diretamente do nó de extração, não do nó anterior
const text = $('Extract from File3').first().json.text || "";
const lines = text.split('\n'); // Divide o texto em linhas reais
const maxCharsPerChunk = 10000; // Limite de segurança
let currentChunk = "";
const chunks = [];

for (const line of lines) {
    // Se a linha atual + o que já temos passar do limite, fecha o lote
    if ((currentChunk.length + line.length) > maxCharsPerChunk && currentChunk.length > 0) {
        chunks.push({ json: { textChunk: currentChunk } });
        currentChunk = "";
    }
    currentChunk += line + "\n";
}

// Adiciona o último pedaço que sobrou
if (currentChunk.length > 0) {
    chunks.push({ json: { textChunk: currentChunk } });
}

return chunks;

